document.addEventListener("DOMContentLoaded",()=>{let e=JSON.parse(localStorage.getItem("meditation_stats")||'{"totalSessions": 0, "causes": {}}');window.logParticipation=function(n){e.totalSessions++,e.causes[n]=(e.causes[n]||0)+1,localStorage.setItem("meditation_stats",JSON.stringify(e)),t(),console.log(`Participated in ${n}. Total sessions: ${e.totalSessions}`)};function t(){const t=document.getElementById("user-total-sessions");t&&(t.textContent=e.totalSessions,t.animate([{transform:"scale(1)"},{transform:"scale(1.1)"},{transform:"scale(1)"}],{duration:500,easing:"ease-out"}))}t()})